const input = $input.first().json;
const action = input.action || 'search_recipe';

function formatMeal(meal) {
  let result = meal.strMeal;
  if (meal.strArea) result += ' (' + meal.strArea + ')';
  if (meal.strCategory) result += ' — ' + meal.strCategory;
  result += '\n';

  // Ingredients
  const ingredients = [];
  for (let i = 1; i <= 20; i++) {
    const ing = meal['strIngredient' + i];
    const measure = meal['strMeasure' + i];
    if (ing && ing.trim()) {
      ingredients.push((measure ? measure.trim() + ' ' : '') + ing.trim());
    }
  }
  if (ingredients.length > 0) {
    result += '\nIngredients:\n';
    ingredients.forEach(ing => { result += '  - ' + ing + '\n'; });
  }

  // Instructions
  if (meal.strInstructions) {
    result += '\nInstructions:\n' + meal.strInstructions.trim() + '\n';
  }

  // Tags
  if (meal.strTags) {
    result += '\nTags: ' + meal.strTags + '\n';
  }

  // Source/YouTube
  if (meal.strYoutube) {
    result += 'Video: ' + meal.strYoutube + '\n';
  }
  if (meal.strSource) {
    result += 'Source: ' + meal.strSource + '\n';
  }

  return result;
}

if (action === 'search_recipe') {
  const query = input.query;
  if (!query) {
    return [{ json: { error: 'Parameter "query" is required (recipe name or keyword).' } }];
  }

  try {
    const data = await helpers.httpRequest({
      method: 'GET',
      url: 'https://www.themealdb.com/api/json/v1/1/search.php?s=' + encodeURIComponent(query)
    });

    if (!data.meals || data.meals.length === 0) {
      return [{ json: { error: 'No recipes found for "' + query + '". Try a different search term.' } }];
    }

    // Show first result in detail, list others briefly
    let result = formatMeal(data.meals[0]);

    if (data.meals.length > 1) {
      result += '\n---\nMore results (' + (data.meals.length - 1) + '):\n';
      data.meals.slice(1, 5).forEach(m => {
        result += '  - ' + m.strMeal;
        if (m.strArea) result += ' (' + m.strArea + ')';
        if (m.strCategory) result += ' — ' + m.strCategory;
        result += '\n';
      });
      if (data.meals.length > 5) {
        result += '  (' + (data.meals.length - 5) + ' more omitted)';
      }
    }

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to search recipes: ' + err.message } }];
  }

} else if (action === 'random_recipe') {
  try {
    const data = await helpers.httpRequest({
      method: 'GET',
      url: 'https://www.themealdb.com/api/json/v1/1/random.php'
    });

    if (!data.meals || data.meals.length === 0) {
      return [{ json: { error: 'Could not fetch a random recipe.' } }];
    }

    return [{ json: { result: formatMeal(data.meals[0]) } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get random recipe: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Use search_recipe or random_recipe.' } }];
}
